import{_ as t,o as a,c as d,ag as i}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"Domains","description":"","frontmatter":{"uid":"cdddc4a1-c802-4c5f-b871-c5ce5d6b5f78 ... ..."},"headers":[],"relativePath":"10_core/30_data/30_domains.md","filePath":"10_core/30_data/30_domains.md"}'),o={name:"10_core/30_data/30_domains.md"};function s(n,e,r,c,l,m){return a(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="domains" tabindex="-1">Domains <a class="header-anchor" href="#domains" aria-label="Permalink to &quot;Domains&quot;">​</a></h1><p>Domains in QiOS are ownership boundaries first. Historically they mapped to Postgres schemas in Supabase, but that layer is now legacy/reference-only or future/conditional unless a specific job requires it. No new domain logic belongs in <code>public</code>.</p><h2 id="domain-hierarchy" tabindex="-1">Domain Hierarchy <a class="header-anchor" href="#domain-hierarchy" aria-label="Permalink to &quot;Domain Hierarchy&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>band -&gt; domain -&gt; subdomain -&gt; object</span></span></code></pre></div><p>Every object must have a resolved path through this hierarchy before it can be considered registered.</p><h2 id="live-domain-map" tabindex="-1">Live Domain Map <a class="header-anchor" href="#live-domain-map" aria-label="Permalink to &quot;Live Domain Map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Domain</th><th>Schema</th><th>Band</th><th>Core Tables</th></tr></thead><tbody><tr><td>QiOne Platform</td><td><code>qione</code></td><td>Platform</td><td>legacy/future tenants, tenant_members, member_roles, tenant_modules, module_role_access</td></tr><tr><td>QiArchive</td><td><code>qiarchive</code></td><td>Core</td><td>archive_files, archive_chunks, ingest_jobs, file_history</td></tr><tr><td>QiGraph</td><td><code>qigraph</code></td><td>Core</td><td>edges, master_index</td></tr><tr><td>QiAlly (AI)</td><td><code>qially</code></td><td>Core</td><td>sessions, messages, memory_embeddings</td></tr><tr><td>QiSys</td><td><code>qisys</code></td><td>Core</td><td>jobs, system_events, worker_status</td></tr><tr><td>QiCase</td><td><code>qicase</code></td><td>Domain</td><td>cases, phases, issues, deadlines, case_documents, document_issues</td></tr><tr><td>QiChronicle</td><td><code>qichronicle</code></td><td>Domain</td><td>events, calendar_feeds</td></tr><tr><td>QiCMS</td><td><code>qicms</code></td><td>Domain</td><td>posts</td></tr><tr><td>QiHome</td><td><code>qihome</code></td><td>Domain</td><td>chores, chore_assignments, expenses, expense_shares, settlements</td></tr><tr><td>QiKnowledge</td><td><code>qiknowledge</code></td><td>Domain</td><td>notes</td></tr><tr><td>QiTax</td><td><code>qitax</code></td><td>Domain</td><td>returns, return_files</td></tr><tr><td>QiVault</td><td><code>qivault</code></td><td>Domain</td><td>documents</td></tr></tbody></table><h2 id="domain-rules" tabindex="-1">Domain Rules <a class="header-anchor" href="#domain-rules" aria-label="Permalink to &quot;Domain Rules&quot;">​</a></h2><ul><li>If a relational layer is used, prefer one schema per domain</li><li>Multi-tenant <code>tenant_id</code> assumptions are legacy/future only unless a specific job reactivates them</li><li>If a relational layer is used, every domain table should have governed access policy coverage</li><li>Cross-domain reads are reference-only unless an explicit interface or event contract is approved</li><li>New domains require an ADR before any new relational schema is created</li></ul><h2 id="domain-vs-namespace-clarification" tabindex="-1">Domain vs Namespace Clarification <a class="header-anchor" href="#domain-vs-namespace-clarification" aria-label="Permalink to &quot;Domain vs Namespace Clarification&quot;">​</a></h2><p>Domains and namespaces are not interchangeable.</p><ul><li>Domains define ownership boundaries in the system architecture.</li><li>Namespace codes define routing containers for work, artifacts, and workspace organization.</li></ul><p>Examples:</p><ul><li><code>QiArchive</code> is a domain</li><li><code>0300LGL</code> is a namespace band</li><li><code>5441MAT</code> is a namespace allocation</li></ul><p>Shorthand legacy codes may exist as aliases in reconciled materials, but they do not replace canonical domain names in the blueprint.</p>',15)])])}const u=t(o,[["render",s]]);export{p as __pageData,u as default};
